import os
import asyncio
from fastapi import FastAPI, HTTPException, Request, BackgroundTasks
from fastapi.responses import StreamingResponse
from fastapi.staticfiles import StaticFiles
from fastapi.middleware.cors import CORSMiddleware
from pydantic import BaseModel
from typing import Optional, List, Dict, Any

from .database import SimpleDB
from .engine import TrustShieldEngine

app = FastAPI(title="TrustShield AI Backend", version="1.0.0")

# Enable CORS for local dev
app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)

db = SimpleDB()
engine = TrustShieldEngine()

# SSE clients list
sse_clients: List[asyncio.Queue] = []

class ScanRequest(BaseModel):
    item: str
    type: str # "Email", "URL", "Video", "Text / Prompt", "Text", etc.
    source: Optional[str] = "Web Dashboard"
    filename: Optional[str] = ""

class IntegrationUpdateRequest(BaseModel):
    connected: bool
    token: str
    webhook: Optional[str] = ""

class WebhookPayload(BaseModel):
    sender: str
    content: str
    channel: Optional[str] = None
    attachment_name: Optional[str] = None

async def broadcast_event(event_type: str, data: Dict[str, Any]):
    """Broadcasts an event to all connected SSE clients."""
    import json
    payload = json.dumps({"event": event_type, "data": data})
    for queue in sse_clients:
        await queue.put(payload)

@app.get("/api/scans")
def get_scans():
    return db.get_scans()

@app.post("/api/scan")
async def execute_scan(req: ScanRequest):
    # Run analysis
    analysis = engine.analyze(req.item, req.type, req.filename)

    # Write to DB
    scan_entry = db.add_scan({
        "item": req.item,
        "type": req.type,
        "risk_score": analysis["risk_score"],
        "result": analysis["result"],
        "source": req.source or "Web Dashboard",
        "details": analysis["explanation"]
    })

    # Broadcast to dashboard in real-time
    await broadcast_event("new_scan", {
        "scan": scan_entry,
        "stats": db.get_stats()
    })

    return {
        "scan": scan_entry,
        "analysis": analysis
    }

@app.get("/api/stats")
def get_stats():
    return db.get_stats()

@app.get("/api/integrations")
def get_integrations():
    return db.get_integrations()

@app.post("/api/integrations/{platform}")
def update_integration(platform: str, req: IntegrationUpdateRequest):
    res = db.update_integration(platform, req.connected, req.token, req.webhook)
    if not res:
        raise HTTPException(status_code=404, detail="Platform not supported")
    return res

@app.post("/api/integrations/webhook/{platform}")
async def handle_social_webhook(platform: str, payload: WebhookPayload):
    """
    Stateless Universal Trust Adapter endpoint.
    Strips platform specific wrappers, parses vectors, and scans content.
    """
    integrations = db.get_integrations()
    if platform not in integrations:
        raise HTTPException(status_code=404, detail="Integration not found")

    # Check if integration is configured/enabled
    if not integrations[platform]["connected"]:
        raise HTTPException(status_code=400, detail=f"{platform.capitalize()} integration is not connected/enabled")

    # Ingestion adapter rules
    source_channel = f"{platform.capitalize()} ({payload.channel})" if payload.channel else f"{platform.capitalize()} Direct"

    # Detect asset type based on contents & attachment
    item_content = payload.content
    asset_type = "Text"
    filename = ""

    if payload.attachment_name:
        filename = payload.attachment_name
        # classify by file extension
        ext = filename.split(".")[-1].lower()
        if ext in ["mp4", "mov", "avi"]:
            asset_type = "Video"
        elif ext in ["mp3", "wav", "aac"]:
            asset_type = "Audio"
        elif ext in ["png", "jpg", "jpeg"]:
            asset_type = "Image"
        elif ext in ["pdf", "docx", "xlsx", "zip"]:
            asset_type = "Document"
    elif "http://" in item_content or "https://" in item_content:
        asset_type = "URL"
    elif "ignore previous" in item_content.lower() or "dan" in item_content.lower():
        asset_type = "Text / Prompt"
    elif platform == "gmail":
        asset_type = "Email"

    # Analyze
    analysis = engine.analyze(item_content, asset_type, filename)

    # Log to DB
    scan_entry = db.add_scan({
        "item": item_content if len(item_content) < 80 else item_content[:77] + "...",
        "type": asset_type,
        "risk_score": analysis["risk_score"],
        "result": analysis["result"],
        "source": source_channel,
        "details": analysis["explanation"]
    })

    # Broadcast event to frontend SSE
    await broadcast_event("webhook_alert", {
        "platform": platform,
        "sender": payload.sender,
        "scan": scan_entry,
        "stats": db.get_stats()
    })

    return {
        "status": "processed",
        "verdict": analysis["verdict"],
        "score": analysis["risk_score"],
        "details": analysis["details"]
    }

@app.get("/api/stream")
async def sse_endpoint(request: Request):
    """Real-time SSE event stream for the dashboard."""
    async def event_generator():
        queue = asyncio.Queue()
        sse_clients.append(queue)
        try:
            while True:
                # Check client connection state
                if await request.is_disconnected():
                    break
                try:
                    data = await asyncio.wait_for(queue.get(), timeout=10.0)
                    yield f"data: {data}\n\n"
                except asyncio.TimeoutError:
                    # Keep-alive heartbeat
                    yield ": ping\n\n"
        except asyncio.CancelledError:
            pass
        finally:
            if queue in sse_clients:
                sse_clients.remove(queue)

    return StreamingResponse(event_generator(), media_type="text/event-stream")

# Serve frontend static assets
frontend_dir = os.path.abspath(os.path.join(os.path.dirname(__file__), "..", "frontend"))
if os.path.exists(frontend_dir):
    app.mount("/", StaticFiles(directory=frontend_dir, html=True), name="static")
else:
    print(f"Warning: Static folder '{frontend_dir}' not found. Serving API only.")

/* ==========================================================================
   TrustShield AI Design System & Core Styles
   Theme: Modern Dark Mode, Glassmorphism, Neon Highlights, Premium Micro-Interactions
   ========================================================================== */

:root {
    --bg-base: #06040c;
    --bg-surface: rgba(16, 12, 30, 0.75);
    --bg-surface-solid: #110c22;
    --bg-surface-light: rgba(28, 22, 48, 0.6);
    --border-color: rgba(138, 43, 226, 0.15);
    --border-color-hover: rgba(138, 43, 226, 0.35);

    --text-primary: #f1f0f6;
    --text-secondary: #a3a1b8;
    --text-muted: #6e6b85;

    --color-purple: #8a2be2;
    --color-purple-glow: rgba(138, 43, 226, 0.4);
    --color-teal: #00f5ff;
    --color-teal-glow: rgba(0, 245, 255, 0.4);

    /* Risk Spectrum Colors */
    --color-safe: #10b981;
    --color-suspicious: #3b82f6;
    --color-high-risk: #f59e0b;
    --color-critical: #ef4444;

    --font-sans: 'Outfit', sans-serif;
    --font-mono: 'Space Grotesk', sans-serif;

    --transition-smooth: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    --blur-intensity: 16px;
}

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    scroll-behavior: smooth;
}

body {
    background-color: var(--bg-base);
    background-image: 
        radial-gradient(circle at 10% 20%, rgba(138, 43, 226, 0.08) 0%, transparent 40%),
        radial-gradient(circle at 90% 80%, rgba(0, 245, 255, 0.06) 0%, transparent 45%),
        radial-gradient(circle at 50% 50%, rgba(10, 8, 22, 1) 0%, rgba(5, 3, 10, 1) 100%);
    color: var(--text-primary);
    font-family: var(--font-sans);
    line-height: 1.5;
    overflow-x: hidden;
}

/* Custom Scrollbars */
::-webkit-scrollbar {
    width: 8px;
    height: 8px;
}
::-webkit-scrollbar-track {
    background: #090613;
}
::-webkit-scrollbar-thumb {
    background: #251b3f;
    border-radius: 4px;
}
::-webkit-scrollbar-thumb:hover {
    background: var(--color-purple);
}

/* ==========================================================================
   Typography & Reusable Utilities
   ========================================================================== */

h1, h2, h3, h4, h5, h6 {
    font-family: var(--font-sans);
    font-weight: 700;
    letter-spacing: -0.02em;
}

.text-muted { color: var(--text-muted) !important; }
.text-sm { font-size: 0.875rem; }
.text-xs { font-size: 0.75rem; }
.highlight-purple {
    color: var(--color-purple);
    text-shadow: 0 0 15px var(--color-purple-glow);
}
.text-purple { color: #b784f7; }
.text-amber { color: var(--color-high-risk); }
.text-blue { color: var(--color-suspicious); }

.anchor-offset {
    display: block;
    position: relative;
    top: -40px;
    visibility: hidden;
}

/* Buttons */
.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    font-family: var(--font-sans);
    font-weight: 600;
    font-size: 0.95rem;
    padding: 10px 22px;
    border-radius: 8px;
    cursor: pointer;
    transition: var(--transition-smooth);
    border: 1px solid transparent;
}

.btn-primary {
    background: linear-gradient(135deg, var(--color-purple) 0%, #611cbd 100%);
    color: #fff;
    box-shadow: 0 4px 15px rgba(138, 43, 226, 0.3);
}
.btn-primary:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(138, 43, 226, 0.5);
    background: linear-gradient(135deg, #9940ed 0%, #6e2ad1 100%);
}

.btn-secondary {
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid rgba(255, 255, 255, 0.1);
    color: var(--text-primary);
}
.btn-secondary:hover {
    background: rgba(255, 255, 255, 0.1);
    border-color: rgba(255, 255, 255, 0.2);
}

.btn-outline {
    background: transparent;
    border: 1px solid var(--border-color);
    color: var(--text-primary);
}
.btn-outline:hover {
    border-color: var(--color-purple);
    background: rgba(138, 43, 226, 0.08);
}

.btn-text {
    background: transparent;
    color: var(--color-teal);
    padding: 0;
}
.btn-text:hover {
    color: #40f9ff;
    text-shadow: 0 0 8px rgba(0, 245, 255, 0.3);
}

.btn-block {
    display: flex;
    width: 100%;
}

/* Badges */
.badge {
    display: inline-flex;
    align-items: center;
    padding: 4px 10px;
    border-radius: 6px;
    font-size: 0.75rem;
    font-weight: 700;
    text-transform: uppercase;
}
.badge-success { background: rgba(16, 185, 129, 0.15); color: var(--color-safe); border: 1px solid rgba(16, 185, 129, 0.25); }
.badge-blue { background: rgba(59, 130, 246, 0.15); color: var(--color-suspicious); border: 1px solid rgba(59, 130, 246, 0.25); }
.badge-amber { background: rgba(245, 158, 11, 0.15); color: var(--color-high-risk); border: 1px solid rgba(245, 158, 11, 0.25); }
.badge-danger { background: rgba(239, 68, 68, 0.15); color: var(--color-critical); border: 1px solid rgba(239, 68, 68, 0.25); }
.badge-muted { background: rgba(110, 107, 133, 0.15); color: var(--text-secondary); border: 1px solid rgba(110, 107, 133, 0.25); }

.badge-pulse {
    animation: badge-pulse-anim 2s infinite;
}
@keyframes badge-pulse-anim {
    0% { box-shadow: 0 0 0 0 rgba(138, 43, 226, 0.4); }
    70% { box-shadow: 0 0 0 6px rgba(138, 43, 226, 0); }
    100% { box-shadow: 0 0 0 0 rgba(138, 43, 226, 0); }
}

/* Panels */
.panel {
    background: var(--bg-surface);
    backdrop-filter: blur(var(--blur-intensity));
    border: 1px solid var(--border-color);
    border-radius: 12px;
    padding: 24px;
    transition: var(--transition-smooth);
}
.panel:hover {
    border-color: var(--border-color-hover);
}

/* ==========================================================================
   LANDING VIEW DESIGN (Top Row)
   ========================================================================== */

.landing-section {
    padding: 30px 4%;
    border-bottom: 2px solid rgba(138, 43, 226, 0.1);
    position: relative;
}

.landing-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 50px;
    flex-wrap: wrap;
    gap: 15px;
}

.landing-header .logo {
    display: flex;
    align-items: center;
    gap: 10px;
}

.shield-logo {
    font-size: 2.2rem;
    background: linear-gradient(135deg, var(--color-teal) 0%, var(--color-purple) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    filter: drop-shadow(0 0 8px rgba(138, 43, 226, 0.4));
}

.logo-text {
    font-size: 1.8rem;
    font-weight: 800;
    letter-spacing: -0.5px;
    background: linear-gradient(to right, #fff 40%, #d4bbf5 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
}

.tagline {
    font-family: var(--font-mono);
    font-style: italic;
    color: var(--color-teal);
    font-size: 1rem;
    letter-spacing: 2px;
    text-transform: uppercase;
}

.hackathon-tag {
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid rgba(255, 255, 255, 0.08);
    padding: 6px 14px;
    border-radius: 20px;
    font-size: 0.85rem;
    color: var(--text-secondary);
}

.hero-container {
    display: grid;
    grid-template-columns: 1.2fr 1.3fr 1.1fr;
    gap: 30px;
    align-items: center;
    margin-bottom: 60px;
}

@media (max-width: 1100px) {
    .hero-container {
        grid-template-columns: 1fr;
        gap: 50px;
    }
}

.hero-title {
    font-size: 3.2rem;
    line-height: 1.1;
    margin-bottom: 20px;
}

.hero-description {
    font-size: 1.1rem;
    color: var(--text-secondary);
    margin-bottom: 30px;
    max-width: 480px;
}

.hero-cta-buttons {
    display: flex;
    gap: 15px;
}

/* Center Animated Shield Graphic */
.hero-center {
    position: relative;
    height: 380px;
    display: flex;
    justify-content: center;
    align-items: center;
}

.central-shield {
    position: relative;
    width: 150px;
    height: 150px;
    background: radial-gradient(circle, rgba(23, 14, 49, 0.8) 0%, rgba(9, 6, 20, 0.95) 100%);
    border: 2px solid var(--color-purple);
    border-radius: 50%;
    display: flex;
    justify-content: center;
    align-items: center;
    box-shadow: 0 0 35px var(--color-purple-glow);
    z-index: 5;
}

.main-shield-icon {
    font-size: 5rem;
    color: rgba(138, 43, 226, 0.2);
    position: absolute;
}

.main-brain-icon {
    font-size: 3.2rem;
    color: var(--color-teal);
    position: relative;
    z-index: 6;
    filter: drop-shadow(0 0 10px rgba(0, 245, 255, 0.6));
    animation: pulse-brain 3s infinite ease-in-out;
}

@keyframes pulse-brain {
    0% { transform: scale(1); filter: drop-shadow(0 0 10px rgba(0, 245, 255, 0.6)); }
    50% { transform: scale(1.08); filter: drop-shadow(0 0 20px rgba(0, 245, 255, 0.85)); }
    100% { transform: scale(1); filter: drop-shadow(0 0 10px rgba(0, 245, 255, 0.6)); }
}

.shield-radar-ring {
    position: absolute;
    width: 250px;
    height: 250px;
    border: 1px dashed rgba(0, 245, 255, 0.2);
    border-radius: 50%;
    animation: rotate-radar 20s linear infinite;
}

@keyframes rotate-radar {
    from { transform: rotate(0deg); }
    to { transform: rotate(360deg); }
}

/* Floating Telemetry Nodes */
.telemetry-node {
    position: absolute;
    background: rgba(16, 12, 30, 0.9);
    border: 1px solid var(--border-color);
    padding: 8px 14px;
    border-radius: 8px;
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 0.8rem;
    font-weight: 600;
    box-shadow: 0 4px 15px rgba(0,0,0,0.4);
    z-index: 10;
    animation: float-node 4s ease-in-out infinite;
}

.telemetry-node i {
    color: var(--color-teal);
    font-size: 1rem;
}

.node-phishing { top: 15%; left: 10%; animation-delay: 0s; }
.node-deepfake { top: 10%; right: 10%; animation-delay: 0.8s; }
.node-website { bottom: 20%; right: 5%; animation-delay: 1.5s; }
.node-prompt { bottom: 15%; left: 5%; animation-delay: 2.2s; }
.node-ai { bottom: 5%; left: 45%; animation-delay: 3s; }

@keyframes float-node {
    0% { transform: translateY(0px); }
    50% { transform: translateY(-10px); }
    100% { transform: translateY(0px); }
}

/* Right How it works card */
.how-it-works-card {
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid rgba(255, 255, 255, 0.06);
    border-radius: 12px;
    padding: 24px;
    backdrop-filter: blur(10px);
}

.how-it-works-card h3 {
    margin-bottom: 20px;
    font-size: 1.25rem;
    border-bottom: 1px solid rgba(255,255,255,0.08);
    padding-bottom: 10px;
}

.step-list {
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.step-item {
    display: flex;
    gap: 15px;
}

.step-num {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background: var(--color-purple);
    color: #fff;
    font-weight: 700;
    font-size: 0.85rem;
    display: flex;
    justify-content: center;
    align-items: center;
    flex-shrink: 0;
    box-shadow: 0 0 10px var(--color-purple-glow);
}

.step-content strong {
    font-size: 0.95rem;
    display: block;
    margin-bottom: 4px;
}

.step-content p {
    font-size: 0.8rem;
    color: var(--text-secondary);
}

/* Threat protection cards row & score guide */
.info-row {
    display: grid;
    grid-template-columns: 2.4fr 1.2fr;
    gap: 30px;
    margin-top: 40px;
}

@media (max-width: 1000px) {
    .info-row {
        grid-template-columns: 1fr;
    }
}

.protection-cards h2 {
    font-size: 1.5rem;
    margin-bottom: 20px;
}

.cards-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    gap: 15px;
}

.prot-card {
    background: rgba(255, 255, 255, 0.02);
    border: 1px solid rgba(255, 255, 255, 0.05);
    padding: 20px 15px;
    border-radius: 10px;
    transition: var(--transition-smooth);
}

.prot-card:hover {
    background: rgba(138, 43, 226, 0.05);
    border-color: rgba(138, 43, 226, 0.25);
    transform: translateY(-3px);
}

.prot-card i {
    font-size: 1.8rem;
    margin-bottom: 12px;
    display: block;
}

.card-phishing i { color: #10b981; }
.card-urls i { color: #f59e0b; }
.card-deepfakes i { color: #a855f7; }
.card-prompt i { color: #3b82f6; }
.card-ai i { color: #06b6d4; }

.prot-card h4 {
    font-size: 0.95rem;
    margin-bottom: 8px;
}

.prot-card p {
    font-size: 0.75rem;
    color: var(--text-secondary);
}

/* Score Guide */
.risk-score-guide {
    background: rgba(255, 255, 255, 0.02);
    border: 1px solid rgba(255, 255, 255, 0.05);
    border-radius: 12px;
    padding: 20px;
}

.risk-score-guide h3 {
    font-size: 1.1rem;
    margin-bottom: 15px;
    padding-bottom: 8px;
    border-bottom: 1px solid rgba(255,255,255,0.06);
}

.guide-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.guide-item {
    display: grid;
    grid-template-columns: 75px 85px 1fr;
    font-size: 0.8rem;
    align-items: center;
    padding: 6px 0;
}

.guide-item .range {
    font-family: var(--font-mono);
    font-weight: 600;
}

.guide-item .label {
    font-weight: 700;
}

.guide-item .desc {
    color: var(--text-secondary);
}

.g-safe .label { color: var(--color-safe); }
.g-suspicious .label { color: var(--color-suspicious); }
.g-high .label { color: var(--color-high-risk); }
.g-critical .label { color: var(--color-critical); }

/* ==========================================================================
   DASHBOARD SECURTY PORTAL (Bottom Row)
   ========================================================================== */

.dashboard-section {
    display: flex;
    min-height: 800px;
    border-top: 1px solid rgba(255, 255, 255, 0.05);
}

/* Sidebar styling */
.dashboard-sidebar {
    width: 260px;
    background: rgba(8, 6, 18, 0.95);
    border-right: 1px solid var(--border-color);
    padding: 30px 20px;
    display: flex;
    flex-direction: column;
    flex-shrink: 0;
}

@media (max-width: 850px) {
    .dashboard-section {
        flex-direction: column;
    }
    .dashboard-sidebar {
        width: 100%;
        border-right: none;
        border-bottom: 1px solid var(--border-color);
    }
}

.sidebar-logo {
    display: flex;
    align-items: center;
    gap: 10px;
    margin-bottom: 40px;
}

.sidebar-logo i {
    font-size: 1.5rem;
    color: var(--color-purple);
}

.sidebar-logo span {
    font-weight: 800;
    font-size: 1.25rem;
    letter-spacing: -0.5px;
}

.sidebar-nav {
    display: flex;
    flex-direction: column;
    gap: 8px;
    flex-grow: 1;
}

.nav-btn {
    background: transparent;
    border: none;
    outline: none;
    color: var(--text-secondary);
    font-family: var(--font-sans);
    font-weight: 600;
    font-size: 0.95rem;
    padding: 12px 16px;
    border-radius: 8px;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 12px;
    width: 100%;
    text-align: left;
    transition: var(--transition-smooth);
}

.nav-btn:hover {
    color: var(--text-primary);
    background: rgba(255, 255, 255, 0.03);
}

.nav-btn.active {
    color: #fff;
    background: rgba(138, 43, 226, 0.15);
    border-left: 3px solid var(--color-purple);
}

.nav-btn .badge {
    margin-left: auto;
    font-size: 0.65rem;
    padding: 2px 6px;
}

/* Sidebar Footer Info Card */
.sidebar-footer-card {
    background: radial-gradient(circle at top left, rgba(138, 43, 226, 0.15) 0%, transparent 60%);
    border: 1px solid var(--border-color);
    padding: 20px 15px;
    border-radius: 10px;
    margin-top: 30px;
}

